parameters.query:
SELECT *
FROM leads
ORDER BY created_at DESC;

parameters.jsCode:
const leads = $input.all();
const highValueLeads = leads.filter(
  lead => lead.json.pipeline === 'High value'
).length;
const mediumValueLeads = leads.filter(
  lead => lead.json.pipeline === 'Medium value'
).length;

const lowValueLeads = leads.filter(
  lead => lead.json.pipeline === 'low value'
).length;

const newLeads = leads.filter(
  lead => lead.json.status === 'New'
).length;

const contactedLeads = leads.filter(
  lead => lead.json.status === 'Contacted'
).length;

const meetingLeads = leads.filter(
  lead => lead.json.status === 'Meeting Scheduled'
).length;

const proposalLeads = leads.filter(
  lead => lead.json.status === 'Proposal Sent'
).length;

const wonLeads = leads.filter(
  lead => lead.json.status === 'Won'
).length;

let rows = '';


for (const lead of leads) {

  rows += `
  <tr>
    <td>${lead.json.id}</td>
    <td>${lead.json.name}</td>
    <td>${lead.json.company}</td>
    <td>${lead.json.email}</td>
    <td>${lead.json.budget}</td>
    <td>${lead.json.pipeline}</td>

    <td>
      <select>
        <option ${lead.json.status === 'New' ? 'selected' : ''}>New</option>
        <option ${lead.json.status === 'Contacted' ? 'selected' : ''}>Contacted</option>
        <option ${lead.json.status === 'Meeting Scheduled' ? 'selected' : ''}>Meeting Scheduled</option>
        <option ${lead.json.status === 'Proposal Sent' ? 'selected' : ''}>Proposal Sent</option>
        <option ${lead.json.status === 'Won' ? 'selected' : ''}>Won</option>
        <option ${lead.json.status === 'Lost' ? 'selected' : ''}>Lost</option>
      </select>
    </td>

    <td>
      <a href="https://rinse-upside-oyster.ngrok-free.dev/webhook/update-status?id=${lead.json.id}">
        Update
      </a>
    </td>
  </tr>`;
}
const totalLeads = leads.length;
const html = `

<!DOCTYPE html>
<html>
<head>
<title>Smart Lead CRM Dashboard</title>
<p>Last Updated: ${new Date().toLocaleString()}</p>

<style>
body {
  font-family: Arial, sans-serif;
  padding: 20px;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th, td {
  border: 1px solid #ddd;
  padding: 10px;
}

th {
  background: #f4f4f4;
}
</style>

</head>
<body>

<h1>Smart Lead CRM Dashboard</h1>
<input
type="text"
placeholder="Search Leads..."
style="padding:10px;width:300px;margin-bottom:20px;"
>
<h2>Sales Pipeline</h2>
<div style="padding:15px;border:1px solid #ddd;min-width:120px;">
  <h3>Total Leads</h3>
  <p>${totalLeads}</p>
</div>
<div style="display:flex;gap:15px;margin-bottom:20px;flex-wrap:wrap;">

  <div style="padding:15px;border:1px solid #ddd;min-width:120px;">
    <h3>New</h3>
    <p>${newLeads}</p>
  </div>

  <div style="padding:15px;border:1px solid #ddd;min-width:120px;">
    <h3>Contacted</h3>
    <p>${contactedLeads}</p>
  </div>

  <div style="padding:15px;border:1px solid #ddd;min-width:120px;">
    <h3>Meetings</h3>
    <p>${meetingLeads}</p>
  </div>

  <div style="padding:15px;border:1px solid #ddd;min-width:120px;">
    <h3>Proposals</h3>
    <p>${proposalLeads}</p>
  </div>

  <div style="padding:15px;border:1px solid #ddd;min-width:120px;">
    <h3>Won</h3>
    <p>${wonLeads}</p>
  </div>

</div>
<div style="
display:flex;
gap:20px;
margin-bottom:20px;
">

<div style="
padding:15px;
border:1px solid #ddd;
min-width:150px;
">
<h3>Total Leads</h3>
<p>${leads.length}</p>
<div style="
padding:15px;
border:1px solid #ddd;
min-width:150px;
">
<h3>High Value Leads</h3>
<p>${highValueLeads}</p>

</div>
<div style="
padding:15px;
border:1px solid #ddd;
min-width:150px;
">
<h3>Medium Value Leads</h3>
<p>${mediumValueLeads}</p>
</div>

<div style="
padding:15px;
border:1px solid #ddd;
min-width:150px;
">
<h3>Low Value Leads</h3>
<p>${lowValueLeads}</p>
</div>
</div>

<table>
<tr>
  <th>ID</th>
  <th>Name</th>
  <th>Company</th>
  <th>Email</th>
  <th>Budget</th>
  <th>Pipeline</th>
  <th>Status</th>
  <th>Action</th>
</tr>

${rows}

</table>

</body>
</html>
`;

return [
  {
    json: {
      html
    }
  }
];
